235	// Simple version of "llama_apply_chat_template" that only works with strings
236	// This function uses heuristic checks to determine commonly used template. It is not a jinja parser.
237	int32_t llm_chat_apply_template(
238	    llm_chat_template tmpl,
239	    const std::vector<const llama_chat_message *> & chat,
240	    std::string & dest, bool add_ass) {
241	    // Taken from the research: https://github.com/ggml-org/llama.cpp/issues/5527
242	    std::stringstream ss;
243	    if (tmpl == LLM_CHAT_TEMPLATE_CHATML) {
244	        // chatml template
245	        for (auto message : chat) {
246	            ss << "<|im_start|>" << message->role << "\n" << message->content << "<|im_end|>\n";
247	        }
248	        if (add_ass) {
249	            ss << "<|im_start|>assistant\n";
250	        }
