        std::cout << "\n\n=== " << test_case.name << " (jinja) ===\n\n";
        try {
            auto msgs = messages;
            for (const auto & msg : test_case.extra_conversation) {
                msgs.push_back(simple_msg(msg.role, msg.content));
            }
            auto output = format_using_common(
                                test_case.template_str,
                                test_case.bos_token,
                                test_case.eos_token,
