                std::cout << "Expected:```\n" << expected_output << "\n```";
                std::cout << "-------------------------\n";
                std::cout << "Actual:```\n" << output << "\n```";
                std::cout.flush();
                assert(output == expected_output);
            }
        } catch (const std::exception & e) {
            std::cerr << "ERROR: " << e.what() << "\n";
            assert(false);
        }
    }

    std::cout << "\nOK: All tests passed successfully.\n";

    return 0;
}

